solution: ```c++
class StockPrice {
public:
    StockPrice() {

    }

    void update(int timestamp, int price) {
        prices[timestamp] = price;
        latestTimestamp = timestamp;
    }

    int current() {
        return prices[latestTimestamp];
    }

    int maximum() {
        return *max_element(prices.begin(), prices.end(), [](const auto& a, const auto& b) { return a.second < b.second; });
    }

    int minimum() {
        return *min_element(prices.begin(), prices.end(), [](const auto& a, const auto& b) { return a.second < b.second; });
    }
private:
    map<int, int> prices;
    int latestTimestamp = 0;
};
```
efficiency: HIGH
time complexity: O(1) for most operations, O(n) for finding max/min
space complexity: O(n)
energy implications: LOW 
explanation: Utilizes a map to store timestamps and prices, allowing for O(1) lookup and update times. Finding the maximum and minimum prices requires iterating through the map, resulting in O(n) time complexity.

